import{c as s,cG as a,cb as i,c8 as t,cf as e,cT as d,ce as l}from"./chunks/framework.BlkIsu1j.js";const n=JSON.parse('{"title":"09. 伪指令体系","description":"","frontmatter":{"title":"09. 伪指令体系","outline":"deep","layout":"doc","prev":{"text":"08. 分支与跳转","link":"/lang/assembly/08_branches_jumps"},"next":{"text":"10. 栈与内存布局","link":"/lang/assembly/10_stack_memory_layout"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/09_pseudo_instructions.md","filePath":"lang/assembly/09_pseudo_instructions.md","lastUpdated":1780201856000}'),h={id:"frontmatter-title",tabindex:"-1"};const r=s({name:"lang/assembly/09_pseudo_instructions.md"},[["render",function(s,n,r,p,o,c){return a(),i("div",null,[t("h1",h,[e(d(s.$frontmatter.title)+" ",1),n[0]||(n[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),n[1]||(n[1]=l('<p>第 5-8 章学到的 RISC-V 指令是&quot;硬指令&quot;——CPU 译码器真正识别的机器码。但在日常汇编编程中，几乎没人直接写 <code>addi t0, x0, 42</code> 来加载一个常数——我们通常写 <code>li t0, 42</code>。后者就是伪指令（pseudo-instruction）：汇编器在输出机器码前，将其透明翻译为一条或多条硬指令。理解伪指令的展开规则，是贯通&quot;写的代码&quot;和&quot;执行的代码&quot;之间最后一道桥梁。</p><h2 id="伪指令的概念" tabindex="-1">伪指令的概念 <a class="header-anchor" href="#伪指令的概念" aria-label="Permalink to “伪指令的概念”">​</a></h2><p><strong>伪指令不是 CPU 的指令</strong>。CPU 芯片上只有第 5-8 章介绍的硬指令（及 M/A/F/D 等扩展）。伪指令是汇编器提供的高级助记符，每条伪指令在汇编阶段被替换为 1-6 条硬指令。</p><p><strong>为什么需要伪指令？</strong></p><ol><li><strong>提升可读性</strong>：<code>mv t0, t1</code> 比 <code>addi t0, t1, 0</code> 更清晰地表达&quot;移动&quot;意图</li><li><strong>隐藏复杂度</strong>：<code>la t0, symbol</code> 一条指令背后的展开可能涉及 2-8 条硬指令——取决于符号的地址范围</li><li><strong>可移植性</strong>：同一个 <code>li t0, 0x123456789ABC</code> 在编译器看来自动选择最优序列，程序员不关心底层是 2 条还是 6 条指令</li><li><strong>减少错误</strong>：手工构造 32 位/64 位立即数需要处理符号扩展修正（下文详述），<code>li</code> 伪指令自动处理所有 corner case</li></ol><p><strong>汇编器的角色</strong>：汇编器维护伪指令 → 硬指令展开表。展开是确定性的——给定伪指令和上下文，展开结果永远相同。你可以在汇编列表输出中看到展开结果（<code>gcc -S</code> 或 objdump）。</p><h2 id="核心伪指令展开" tabindex="-1">核心伪指令展开 <a class="header-anchor" href="#核心伪指令展开" aria-label="Permalink to “核心伪指令展开”">​</a></h2><p>下表给出 RISC-V 标准伪指令及对应展开。<strong>一条伪指令展开为一条硬指令</strong>的占大多数——这些本质上只是寄存器的重新解释。</p><h3 id="移动与加载类" tabindex="-1">移动与加载类 <a class="header-anchor" href="#移动与加载类" aria-label="Permalink to “移动与加载类”">​</a></h3><table tabindex="0"><thead><tr><th>伪指令</th><th>等价硬指令</th><th>说明</th></tr></thead><tbody><tr><td><code>mv rd, rs</code></td><td><code>addi rd, rs, 0</code></td><td>寄存器复制</td></tr><tr><td><code>li rd, imm</code></td><td>视立即数大小自动选择（见下文）</td><td>加载任意 64 位立即数</td></tr><tr><td><code>la rd, symbol</code></td><td><code>auipc + addi</code>（或更长链）</td><td>加载符号地址</td></tr><tr><td><code>lla rd, symbol</code></td><td><code>auipc + addi</code>（局部符号）</td><td>加载局部符号地址</td></tr></tbody></table><p>mv 展开为 <code>addi rd, rs, 0</code> 而非 <code>add rd, rs, x0</code>（两者等价）。汇编器偏爱 I-type 变体——I-type <code>addi</code> 和 R-type <code>add</code> 的延迟相同，但 I-type 编码多一个选择。事实上两者完全等效。</p><h3 id="跳转类" tabindex="-1">跳转类 <a class="header-anchor" href="#跳转类" aria-label="Permalink to “跳转类”">​</a></h3><table tabindex="0"><thead><tr><th>伪指令</th><th>等价硬指令</th><th>说明</th></tr></thead><tbody><tr><td><code>j label</code></td><td><code>jal x0, label</code></td><td>无条件跳转</td></tr><tr><td><code>jal label</code></td><td><code>jal x1, label</code></td><td>跳转并链接 ra（等同于 call）</td></tr><tr><td><code>jr rs</code></td><td><code>jalr x0, rs, 0</code></td><td>间接跳转</td></tr><tr><td><code>jalr rs</code></td><td><code>jalr x1, rs, 0</code></td><td>间接调用</td></tr><tr><td><code>ret</code></td><td><code>jalr x0, ra, 0</code></td><td>函数返回</td></tr><tr><td><code>call symbol</code></td><td><code>auipc ra, %pcrel_hi(sym); jalr ra, %pcrel_lo(ra)(sym)</code></td><td>函数调用</td></tr><tr><td><code>tail symbol</code></td><td><code>auipc t1, %pcrel_hi(sym); jalr x0, %pcrel_lo(t1)(sym)</code></td><td>尾调用优化</td></tr></tbody></table><p><code>ret</code> 是 <code>jalr x0, ra, 0</code> 的语法糖——&quot;跳到 ra 存的地址，不记返回地址&quot;。这也是为什么 ra（x1）叫返回地址寄存器：<code>jal</code> 把返回地址写入 ra，<code>ret</code> 从 ra 跳回。</p><h3 id="运算类" tabindex="-1">运算类 <a class="header-anchor" href="#运算类" aria-label="Permalink to “运算类”">​</a></h3><table tabindex="0"><thead><tr><th>伪指令</th><th>等价硬指令</th><th>说明</th></tr></thead><tbody><tr><td><code>nop</code></td><td><code>addi x0, x0, 0</code></td><td>空操作</td></tr><tr><td><code>not rd, rs</code></td><td><code>xori rd, rs, -1</code></td><td>按位取反</td></tr><tr><td><code>neg rd, rs</code></td><td><code>sub rd, x0, rs</code></td><td>取负（0 - rs）</td></tr><tr><td><code>negw rd, rs</code></td><td><code>subw rd, x0, rs</code></td><td>取负（32 位，符号扩展）</td></tr><tr><td><code>sext.w rd, rs</code></td><td><code>addiw rd, rs, 0</code></td><td>将 rs 的低 32 位符号扩展至 64 位</td></tr><tr><td><code>seqz rd, rs</code></td><td><code>sltiu rd, rs, 1</code></td><td>等于零判断：rd = (rs == 0)</td></tr></tbody></table><p><code>not</code> 是 <code>xori rd, rs, -1</code> 的直接体现——<code>-1</code> 的 12 位编码是 <code>0xFFF</code>，符号扩展后是 64 位全 1，异或全 1 = 取反。<code>nop</code> 展开为 <code>addi x0, x0, 0</code>——写 x0 丢弃结果，读 x0 给零，这确实是真正的&quot;什么都不做&quot;。</p><h3 id="分支类" tabindex="-1">分支类 <a class="header-anchor" href="#分支类" aria-label="Permalink to “分支类”">​</a></h3><table tabindex="0"><thead><tr><th>伪指令</th><th>等价硬指令</th><th>说明</th></tr></thead><tbody><tr><td><code>beqz rs, label</code></td><td><code>beq rs, x0, label</code></td><td>等于零分支</td></tr><tr><td><code>bnez rs, label</code></td><td><code>bne rs, x0, label</code></td><td>不等于零分支</td></tr><tr><td><code>blez rs, label</code></td><td><code>bge x0, rs, label</code></td><td>小于等于零分支（有符号）</td></tr><tr><td><code>bgez rs, label</code></td><td><code>bge rs, x0, label</code></td><td>大于等于零分支</td></tr><tr><td><code>bltz rs, label</code></td><td><code>blt rs, x0, label</code></td><td>小于零分支</td></tr><tr><td><code>bgtz rs, label</code></td><td><code>blt x0, rs, label</code></td><td>大于零分支</td></tr><tr><td><code>bgt rs1, rs2, label</code></td><td><code>blt rs2, rs1, label</code></td><td>大于（交换操作数）</td></tr><tr><td><code>ble rs1, rs2, label</code></td><td><code>bge rs2, rs1, label</code></td><td>小于等于（交换操作数）</td></tr><tr><td><code>bgtu rs1, rs2, label</code></td><td><code>bltu rs2, rs1, label</code></td><td>无符号大于</td></tr><tr><td><code>bleu rs1, rs2, label</code></td><td><code>bgeu rs2, rs1, label</code></td><td>无符号小于等于</td></tr></tbody></table><p>分支伪指令是 RISC-V 伪指令体系中最有生产力提升的部分。硬指令只有 6 条（beq/bne/blt/bge/bltu/bgeu），但加上 x0 和操作数交换，能拼出所有常见的比较-分支模式。伪指令给这些组合命名，无需每次都心算操作数交换。</p><h3 id="伪指令组合示例" tabindex="-1">伪指令组合示例 <a class="header-anchor" href="#伪指令组合示例" aria-label="Permalink to “伪指令组合示例”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 完整的 if-else 使用伪指令的写法</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    blt  t0, t1, less      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # blt 本身就是硬指令</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j    not_less           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # j 是伪指令 → jal x0, not_less</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">less:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mv   a0, t1            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # mv 是伪指令 → addi a0, t1, 0</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # ret 是伪指令 → jalr x0, ra, 0</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">not_less:</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    neg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  a0, t0            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # neg 是伪指令 → sub a0, x0, t0</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><p>每条伪指令在汇编列表中可以用 <code>-M no-aliases</code> 选项（GNU objdump）展示真实展开。</p><h2 id="lui-与构造任意立即数" tabindex="-1">LUI 与构造任意立即数 <a class="header-anchor" href="#lui-与构造任意立即数" aria-label="Permalink to “LUI 与构造任意立即数”">​</a></h2><p>立即数的位宽限制是 RISC-V 汇编中最常见的&quot;为什么不能这样写&quot;的根源。I-type 只有 12 位立即数，但程序需要 32 位和 64 位常量。<code>lui</code>（Load Upper Immediate）是构造大立即数的核心。</p><h3 id="lui-指令-u-type" tabindex="-1">LUI 指令（U-type） <a class="header-anchor" href="#lui-指令-u-type" aria-label="Permalink to “LUI 指令（U-type）”">​</a></h3><p><code>lui rd, imm20</code>：rd = imm20 &lt;&lt; 12，低 12 位清零。opcode = <code>0110111</code>。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>U-type: ┌──────────────────────────┬───────┬─────────┐</span></span>\n<span class="line"><span>        │       imm[31:12]         │  rd   │ opcode  │</span></span>\n<span class="line"><span>        └───────────20─────────────┴───5───┴────7────┘</span></span></code></pre></div><p>U-type 牺牲了 rs1、rs2、funct3 字段，换来了 20 位立即数。这是 RISC-V 中立即数最宽的格式。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lui t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x12345</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # t0 = 0x12345 &lt;&lt; 12 = 0x12345_000</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 注意：0x12345 是 20 位（5 个 hex 位），正好填满 U-type 立即数</span></span></code></pre></div><h3 id="构造-32-位值-lui-addi" tabindex="-1">构造 32 位值：LUI + ADDI <a class="header-anchor" href="#构造-32-位值-lui-addi" aria-label="Permalink to “构造 32 位值：LUI + ADDI”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 目标：t0 = 0x12345_678</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lui  t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x12345</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t0 = 0x12345_000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x678</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # t0 = 0x12345_000 + 0x678 = 0x12345_678</span></span></code></pre></div><p>看似简单直接——但这里有一个微妙的陷阱。</p><h3 id="lo12-符号扩展修正" tabindex="-1">lo12 符号扩展修正 <a class="header-anchor" href="#lo12-符号扩展修正" aria-label="Permalink to “lo12 符号扩展修正”">​</a></h3><p>当 lo12（低 12 位立即数）的最高位（bit 11）为 1 时，<code>addi</code> 的符号扩展会将 lo12 解释为负数。<code>lui</code> 设置的 hi20 被符号扩展&quot;吃掉&quot; 1：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 目标：t0 = 0x12345_ABC</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 错误展开：</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lui  t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x12345</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t0 = 0x12345_000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xABC</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 0xABC 符号位 = 1 → 符号扩展为 0xFFFF_FFFF_FFFF_FABC</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # t0 = 0x12345_000 + (-0x544) = 0x12344_ABC  ← 错了！</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 正确展开（汇编器自动处理）：</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lui  t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x12346</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # hi20 预先 +1！（0x12345 + 1 = 0x12346）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xABC</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # t0 = 0x12346_000 + (-0x544) = 0x12345_ABC  ← 正确！</span></span></code></pre></div><p>汇编器的 <code>li</code> 伪指令<strong>自动处理这种修正</strong>。手工写 <code>lui+addi</code> 构造立即数时，程序员必须自己判断是否需要 hi20+1 修正——否则产生难以调试的数值错误。这正是 <code>li</code> 存在的重要原因：把&quot;如何构造 32/64 位立即数&quot;的所有 corner case 交给汇编器。</p><p><strong>修正判定</strong>：当 lo12 的 bit 11 == 1 时，hi20 需要 +1。等价于：如果低 12 位在 <code>[0x800, 0xFFF]</code> 范围内，hi20 加 1。</p><h3 id="构造-64-位值" tabindex="-1">构造 64 位值 <a class="header-anchor" href="#构造-64-位值" aria-label="Permalink to “构造 64 位值”">​</a></h3><p>64 位立即数的构造最多需要 6 条指令（2 次 lui+addi + 移位 + 合并）：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 目标：t0 = 0x12345678_9ABCDEF0</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># li 伪指令自动展开，以下是手动展开示例：</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lui  t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x12345</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t0[63:32] 高半部分 hi20</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x678</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 可能触发 +1 修正</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 左移到高 32 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lui  t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x9ABCD</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t1[31:0] 低半部分 hi20</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xEF0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 同样可能触发修正</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">or</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t0, t0, t1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 合并高低半部分</span></span></code></pre></div><p>实际上汇编器的 <code>li</code> 展开会更智能——根据立即数中 1 的密度选择 <code>lui+addi</code> 的 2-6 指令序列、或者用 <code>addi+移位</code> 组合、或者加载立即数池（literal pool）。程序员不需要关心细节——<code>li</code> 保证&quot;最正确&quot;的展开。</p><h3 id="汇编器的-li-展开策略总结" tabindex="-1">汇编器的 li 展开策略总结 <a class="header-anchor" href="#汇编器的-li-展开策略总结" aria-label="Permalink to “汇编器的 li 展开策略总结”">​</a></h3><table tabindex="0"><thead><tr><th>立即数范围</th><th>展开</th><th>指令数</th></tr></thead><tbody><tr><td>[-2048, 2047]</td><td><code>addi rd, x0, imm</code></td><td>1</td></tr><tr><td>12 位无符号 [0, 4095]</td><td><code>ori rd, x0, imm</code>（某些汇编器选用）</td><td>1</td></tr><tr><td>32 位以内</td><td><code>lui + addi</code></td><td>2</td></tr><tr><td>32 位，lo12 需修正</td><td><code>lui(hi20+1) + addi(负lo12修正)</code></td><td>2</td></tr><tr><td>64 位</td><td><code>lui+addi+slli+lui+addi+or</code> 或类似序列</td><td>6</td></tr><tr><td>位模式特殊（如全 1）</td><td><code>addi rd, x0, -1</code></td><td>1</td></tr></tbody></table><h2 id="条件伪指令" tabindex="-1">条件伪指令 <a class="header-anchor" href="#条件伪指令" aria-label="Permalink to “条件伪指令”">​</a></h2><p>前面的分支伪指令表中已列出完整列表。这里补充关键的两个：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 无符号的大于/小于等于</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bgtu a0, a1, label   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 展开为 bltu a1, a0, label</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bleu a0, a1, label   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 展开为 bgeu a1, a0, label</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 与零比较的便捷形式</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">beqz a0, is_zero      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 展开为 beq a0, x0, is_zero</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bnez a0, not_zero     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 展开为 bne a0, x0, not_zero</span></span></code></pre></div><p><code>beqz</code>/<code>bnez</code> 可能是被使用频率最高的伪指令——与零比较是 C 语言中 <code>if (ptr)</code>、<code>if (count)</code>、<code>while (*p)</code> 的直接翻译。</p><h2 id="auipc-位置无关代码的基石" tabindex="-1">AUIPC：位置无关代码的基石 <a class="header-anchor" href="#auipc-位置无关代码的基石" aria-label="Permalink to “AUIPC：位置无关代码的基石”">​</a></h2><p><code>auipc rd, imm20</code>（Add Upper Immediate to PC）是 U-type 的另一条指令，opcode = <code>0010111</code>。它是 RISC-V 实现位置无关代码（PIC）的核心。</p><p><strong>语义</strong>：rd = PC + (imm20 &lt;&lt; 12)</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">auipc t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # t0 = PC（读取自己的 PC 值！）</span></span></code></pre></div><p><code>auipc t0, 0</code> 是获取当前 PC 值的唯一方法——RISC-V 不设&quot;读 PC&quot;指令。结合 <code>jalr</code> 或 <code>addi</code>，<code>auipc</code> 可以访问 ±2GB 范围内的任何代码或数据地址。</p><h3 id="la-伪指令的展开" tabindex="-1">la 伪指令的展开 <a class="header-anchor" href="#la-伪指令的展开" aria-label="Permalink to “la 伪指令的展开”">​</a></h3><p><code>la rd, symbol</code> 根据符号的范围自动选择展开：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 近符号（±2GB 内）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">la t0, near_var</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → auipc t0, %pcrel_hi(near_var)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   addi  t0, t0, %pcrel_lo(near_var)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 远符号（超出 ±2GB，需要 GOT 间接寻址）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">la t0, far_var</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → auipc t0, %got_pcrel_hi(far_var)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   ld    t0, %got_pcrel_lo(t0)(far_var)  # 通过 GOT 间接加载</span></span></code></pre></div><p><code>%pcrel_hi(sym)</code> 和 <code>%pcrel_lo(sym)</code> 是汇编器的<strong>重定位操作数</strong>（relocation operand）——它们不是立即数，而是&quot;此处填符号相对 PC 的高/低部分&quot;的占位符，链接器在最终链接时填入具体值。</p><h3 id="call-伪指令的展开" tabindex="-1">call 伪指令的展开 <a class="header-anchor" href="#call-伪指令的展开" aria-label="Permalink to “call 伪指令的展开”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> my_func</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → auipc ra, %pcrel_hi(my_func)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   jalr ra, %pcrel_lo(ra)(my_func)</span></span></code></pre></div><p>注意 <code>jalr</code> 的偏移使用的是 ra（当前指令的 PC 相关值）的相对偏移——这和 lo12 修正同理。链接器会处理所有重定位计算。</p><h3 id="位置无关代码的实际意义" tabindex="-1">位置无关代码的实际意义 <a class="header-anchor" href="#位置无关代码的实际意义" aria-label="Permalink to “位置无关代码的实际意义”">​</a></h3><p>动态共享库（.so）和 PIE（Position-Independent Executable）可执行文件依赖 AUIPC 实现运行时重定位。当加载器将 .so 加载到任意基地址时，库中的 <code>la</code>/<code>call</code> 通过 AUIPC 自动算出正确的运行时地址——无需修改代码段（代码段在进程间共享节省物理内存）。这是现代 OS 安全机制（ASLR——地址空间布局随机化）和内存效率的基础。</p><h2 id="伪指令的透明性与调试" tabindex="-1">伪指令的透明性与调试 <a class="header-anchor" href="#伪指令的透明性与调试" aria-label="Permalink to “伪指令的透明性与调试”">​</a></h2><p>伪指令对执行是透明的——CPU 看不见它们。但调试时需要能&quot;看穿&quot;伪指令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反汇编时显示伪指令（默认）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">riscv64-unknown-elf-objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program.elf</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反汇编时只显示硬指令（去掉伪指令别名）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">riscv64-unknown-elf-objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> no-aliases</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program.elf</span></span></code></pre></div><p>使用 <code>-M no-aliases</code> 可以看到硬件真正执行的指令序列——这对于排查汇编器 bug 或优化指令计数很有价值。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>伪指令不是 CPU 指令，汇编器将其透明展开为 1-6 条硬指令——mv/li/la/call/ret/j/nop 是最常用的核心伪指令</li><li>LUI（U-type）加载 20 位立即数到高位，与 ADDI 组合构造 32 位常数——lo12 符号扩展修正（hi20+1）由汇编器自动处理</li><li>li 伪指令根据立即数大小自动选择 1-6 条最优指令序列，程序员无需关心 hi20 修正细节</li><li>分支伪指令（beqz/bnez/bgt/ble 等）通过 x0 和操作数交换补全硬指令 6 条分支的语义空白</li><li>AUIPC 是 PIC/PIE 的基石——la/call 伪指令底层使用 auipc+jalr 实现 ±2GB 范围的地址和跳转</li></ul>',68))])}]]);export{n as __pageData,r as default};
